import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";

export default function MusicScanner() {
  const [song, setSong] = useState(null);

  const handleScan = (result) => {
    if (!result?.[0]?.rawValue) return;

    const code = result[0].rawValue.trim(); // np. "song_1"

    setSong({
      title: code,
      artist: "Nieznany wykonawca",
      file: `${code}.mp3`,
    });
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>🎵 QR Music Scanner</h1>

      {!song && (
        <>
          <p>Zeskanuj kod QR z informacjami o piosence.</p>

          <Scanner
  onScan={handleScan}
  components={{ finder: true }}
  constraints={{
    video: {
      facingMode: { ideal: "environment" } // NIE wymusza, nie powoduje błędu
    }
  }}
/>
        </>
      )}

      {song && (
        <div style={{ marginTop: 20 }}>
          <h2>{song.title}</h2>
          <h3>{song.artist}</h3>

          <audio
            controls
            src={`/audio/${song.file}`}
            style={{ width: "100%" }}
          />

          <button
            onClick={() => setSong(null)}
            style={{
              marginTop: 20,
              padding: "10px 20px",
              fontSize: 16,
            }}
          >
            Skanuj kolejną piosenkę
          </button>
        </div>
      )}
    </div>
  );
}
